changeSet.sql:
CREATE TABLE iam_user_attributes ( id VARCHAR(36) PRIMARY KEY REFERENCES user_entity(id), expiry_date TIMESTAMP WITHOUT TIME ZONE NOT NULL, inactivity_notification_sent BOOLEAN DEFAULT false, expired_notification_sent BOOLEAN DEFAULT false );
CREATE TABLE iam_mail_list ( id SERIAL PRIMARY KEY, name VARCHAR NOT NULL, UNIQUE(name) );
CREATE TABLE iam_mail_list_user ( mail_list_id INTEGER REFERENCES iam_mail_list(id) ON DELETE CASCADE, user_id VARCHAR(36) REFERENCES user_entity(id), PRIMARY KEY (mail_list_id, user_id) );
CREATE TABLE iam_mail_type ( id INTEGER PRIMARY KEY, name VARCHAR NOT NULL );
CREATE TABLE iam_mail ( id SERIAL PRIMARY KEY, send_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(), expiry_date TIMESTAMP WITH TIME ZONE, sender VARCHAR NOT NULL, text VARCHAR NOT NULL, subject VARCHAR NOT NULL, archived BOOLEAN NOT NULL, type INTEGER NOT NULL REFERENCES iam_mail_type(id), recipient INTEGER NOT NULL REFERENCES iam_mail_list(id), user_id VARCHAR(36) NOT NULL REFERENCES iam_user_attributes(id) );
CREATE TABLE iam_institution_category ( name VARCHAR PRIMARY KEY );
CREATE TABLE iam_institution ( id SERIAL PRIMARY KEY, name VARCHAR NOT NULL UNIQUE, short_name VARCHAR NOT NULL UNIQUE, service_building_street VARCHAR NOT NULL, service_building_postal_code VARCHAR NOT NULL, service_building_location VARCHAR NOT NULL, address_street VARCHAR, address_postal_code VARCHAR, address_location VARCHAR, central_phone VARCHAR NOT NULL, central_fax VARCHAR, central_mail VARCHAR NOT NULL, imis_id VARCHAR, imis_usergroup_id VARCHAR(3) NOT NULL, x_coordinate FLOAT, y_coordinate FLOAT, active BOOLEAN DEFAULT true );
CREATE TABLE iam_institution_central_alarm_mail_addresses ( institution_id INTEGER REFERENCES iam_institution, mail VARCHAR, PRIMARY KEY(institution_id, mail) );
CREATE TABLE iam_institution_central_alarm_phone_numbers ( institution_id INTEGER REFERENCES iam_institution, phone VARCHAR, PRIMARY KEY(institution_id, phone) );
CREATE TABLE iam_institution_categories ( institution_id INTEGER REFERENCES iam_institution(id), category_name VARCHAR REFERENCES iam_institution_category, PRIMARY KEY (institution_id, category_name) );
CREATE TABLE iam_institution_user ( institution_id INTEGER REFERENCES iam_institution(id) ON DELETE CASCADE, user_id VARCHAR(36) REFERENCES iam_user_attributes(id), PRIMARY KEY(institution_id, user_id) );
CREATE TABLE iam_event ( id SERIAL PRIMARY KEY, start_date TIMESTAMP WITH TIME ZONE NOT NULL, end_date TIMESTAMP WITH TIME ZONE NOT NULL, title VARCHAR NOT NULL, site VARCHAR NOT NULL, description VARCHAR NOT NULL );
